// English lives at the root; the other languages (incl. Swedish at /sv/) live
// under a /<lang>/ prefix.
const ROOT_LANG = "en";
const PREFIXED = SUPPORTED.filter((l) => l !== ROOT_LANG);

// The language a pathname encodes via its prefix (e.g. "/sv/lag/x" -> "sv"),
// or null when there is no prefix (English root).
export function pathLang(pathname) {
  const p =
    pathname ?? (typeof window !== "undefined" ? window.location.pathname : "/");
  const m = p.match(/^\/([a-z]{2})(?=\/|$)/);
  return m && PREFIXED.includes(m[1]) ? m[1] : null;
}

// Drop any language prefix, leaving the bare route ("/", "/lag/x/", ...).
export function stripLangPrefix(pathname) {
  const bare = pathname.replace(/^\/([a-z]{2})(?=\/|$)/, (s, l) =>
    PREFIXED.includes(l) ? "" : s
  );
  return bare || "/";
}

// Re-attach the prefix for a target language (English keeps the bare route).
export function localizedPath(pathname, lang) {
  const bare = stripLangPrefix(pathname);
  if (lang === ROOT_LANG) return bare;
  return bare === "/" ? `/${lang}/` : `/${lang}${bare}`;
}

export function detectLang() {
  const fromUrl = pathLang();
  if (fromUrl) return fromUrl;
  const saved = localStorage.getItem("lang");
  if (saved && SUPPORTED.includes(saved)) return saved;
  for (const l of navigator.languages || [navigator.language || ""]) {
    const base = l.split("-")[0].toLowerCase();
    if (SUPPORTED.includes(base)) return base;
  }
  return "en";
}

const I18nCtx = createContext(null);

export function I18nProvider({ children }) {
  const [lang, setLang] = useState(detectLang);
  useEffect(() => {
    localStorage.setItem("lang", lang);
    document.documentElement.lang = lang;
  }, [lang]);

  const t = (key, vars) => {
    let s = STRINGS[lang]?.[key] ?? STRINGS.en[key] ?? STRINGS.sv[key] ?? key;
    if (vars) for (const k in vars) s = s.split(`{${k}}`).join(vars[k]);
    return s;
  };
  const tn = (svName) =>
    lang === "sv" ? svName : TEAM_NAMES[lang]?.[svName] ?? svName;

  return (
    <I18nCtx.Provider value={{ lang, setLang, t, tn }}>
      {children}
    </I18nCtx.Provider>
  );
}

export const useI18n = () => useContext(I18nCtx);
